{"filecontent":null,"copy":"<!-- Last modified Fri Oct 31 8:04AM -->
<!-- Last modified Thu Oct 30 4:36PM -->
<!-- Last modified Thu Oct 30 4:26PM -->
<!-- Last modified Thu Sep 18 2:20PM -->
<!-- Page: lvxdata - User Activity Report -->

{% comment %} Query last 30 days of log data {% endcomment %}
{% fetchxml userActivityLogs %}
<fetch>
  <entity name="lv_log">
    <attribute name="createdon" />
    <attribute name="lv_userfullname" />
    <attribute name="lv_kind" />
    <attribute name="lv_detail" />
    <attribute name="lv_memo" />
    <filter>
      <condition attribute="createdon" operator="last-x-days" value="30" />
    </filter>
    <order attribute="createdon" descending="false" />
  </entity>
</fetch>
{% endfetchxml %}

<!-- DEBUG: FetchXML query returned {{ userActivityLogs.results.entities.size }} records -->
<!-- DEBUG: Has entities? {% if userActivityLogs.results.entities %}YES{% else %}NO{% endif %} -->

<div class="container-fluid mt-4">
    <!-- Header -->
    <div class="row mb-4">
        <div class="col-12">
            <div class="card">
                <div class="card-header">
                    <h4 class="mb-0">
                        <i class="fas fa-chart-line"></i> User Activity Report - Last 30 Days
                    </h4>
                    <small class="text-muted">Daily activity summary for the last 30 days</small>
                </div>
            </div>
        </div>
    </div>

    <!-- Controls -->
    <div class="row mb-4">
        <div class="col-12">
            <div class="card">
                <div class="card-header">
                    <h5 class="mb-0">Filter Controls</h5>
                </div>
                <div class="card-body">
                    <div class="row g-3">
                        <div class="col-md-6">
                            <label for="userInclusionToggle" class="form-label">User Inclusion:</label>
                            <select class="form-control" id="userInclusionToggle" onchange="applyUserFilter()">
                                <option value="exclude" selected>Exclude Test/Admin Users (Default)</option>
                                <option value="all">Include All Users</option>
                            </select>
                        </div>
                        <div class="col-md-6">
                            <label for="chartViewToggle" class="form-label">View Mode:</label>
                            <select class="form-control" id="chartViewToggle" onchange="toggleView()">
                                <option value="table" selected>Table View</option>
                                <option value="chart">Chart View</option>
                            </select>
                        </div>
                    </div>
                    <div class="row mt-3">
                        <div class="col-12">
                            <div class="alert alert-info mb-0">
                                <i class="fas fa-info-circle"></i>
                                <strong>Excluded Users (Default):</strong> Loanvisiontesting, Robert Martin, Michael LeBuhn
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <!-- Summary Stats -->
    <div class="row mb-4">
        <div class="col-md-3">
            <div class="card bg-primary text-white">
                <div class="card-body">
                    <h5 class="card-title">Total Log Entries</h5>
                    <h2 class="mb-0" id="totalLogEntries">{{ userActivityLogs.results.entities.size }}</h2>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card bg-success text-white">
                <div class="card-body">
                    <h5 class="card-title">Unique Users</h5>
                    <h2 class="mb-0" id="uniqueUsers">-</h2>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card bg-info text-white">
                <div class="card-body">
                    <h5 class="card-title">Avg Daily Activity</h5>
                    <h2 class="mb-0" id="avgDailyActivity">-</h2>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card bg-warning text-white">
                <div class="card-body">
                    <h5 class="card-title">Most Active Day</h5>
                    <h2 class="mb-0" id="mostActiveDay">-</h2>
                </div>
            </div>
        </div>
    </div>

    <!-- Main Report -->
    <div class="row">
        <div class="col-12">
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Daily Activity Breakdown</h5>
                    <span class="badge bg-secondary" id="statusBadge">Processing...</span>
                </div>
                <div class="card-body">
                    <!-- Table View -->
                    <div id="tableView">
                        <div class="table-responsive">
                            <table class="table table-striped table-hover" id="activityTable">
                                <thead class="table-dark">
                                    <tr>
                                        <th style="width: 120px;">Date</th>
                                        <th style="width: 100px;">Day</th>
                                        <th style="width: 120px;">Total Logs</th>
                                        <th style="width: 120px;">Unique Users</th>
                                        <th>Activity Bar</th>
                                        <th style="width: 100px;">% of Max</th>
                                    </tr>
                                </thead>
                                <tbody id="activityTableBody">
                                    <tr>
                                        <td colspan="6" class="text-center">
                                            <i class="fas fa-spinner fa-spin"></i> Processing activity data...
                                        </td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <!-- Chart View (initially hidden) -->
                    <div id="chartView" style="display: none;">
                        <canvas id="activityChart" width="400" height="200"></canvas>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

<script>
// Build JavaScript array directly - SIMPLEST POSSIBLE APPROACH
const rawLogData = [];
{%- for log in userActivityLogs.results.entities -%}
rawLogData.push({
    createdon: "{{ log.createdon | date: "yyyy-MM-ddTHH:mm:ss" }}",
    username: decodeURIComponent("{{ log.lv_userfullname | url_encode }}"),
    kind: decodeURIComponent("{{ log.lv_kind | url_encode }}"),
    detail: decodeURIComponent("{{ log.lv_detail | url_encode }}"),
    memo: decodeURIComponent("{{ log.lv_memo | url_encode }}")
});
{%- endfor -%}

// Shared user exclusion logic (matches lvxcpquery pattern + Michael LeBuhn)
const UserExclusionFilters = {
    // Updated regex pattern to include Michael LeBuhn
    getExclusionRegex: function() {
        return /^(?!.*Loanvisiontesting)(?!.*Loan Vision)(?!.*Robert Martin)(?!.*Michael LeBuhn).*$/i;
    },

    // Apply exclusion filter to username
    shouldIncludeUser: function(username, includeAll = false) {
        if (includeAll) return true;
        if (!username) return false;
        return this.getExclusionRegex().test(username);
    },

    // Get list of excluded usernames for display
    getExcludedUsernames: function() {
        return ['Loanvisiontesting', 'Loan Vision', 'Robert Martin', 'Michael LeBuhn'];
    }
};

// Main processing variables
let processedData = {};
let dailyStats = [];
let maxDailyLogs = 0;
let maxDailyUsers = 0;

function processLogData() {
    const includeAllUsers = document.getElementById('userInclusionToggle').value === 'all';

    // Reset processing data
    processedData = {};
    const uniqueUsers = new Set();

    // Process each log entry
    rawLogData.forEach(log => {
        const shouldInclude = UserExclusionFilters.shouldIncludeUser(log.username, includeAllUsers);

        if (!shouldInclude) {
            return; // Skip excluded users
        }

        const logDate = new Date(log.createdon);
        const dateKey = logDate.toISOString().split('T')[0]; // YYYY-MM-DD format

        // Initialize date if not exists
        if (!processedData[dateKey]) {
            processedData[dateKey] = {
                date: dateKey,
                totalLogs: 0,
                uniqueUsers: new Set(),
                logs: []
            };
        }

        // Add to daily data
        processedData[dateKey].totalLogs++;
        processedData[dateKey].uniqueUsers.add(log.username);
        processedData[dateKey].logs.push(log);

        // Track overall unique users
        uniqueUsers.add(log.username);
    });

    // Convert to array and sort by date
    dailyStats = Object.values(processedData).map(day => ({
        date: day.date,
        totalLogs: day.totalLogs,
        uniqueUsers: day.uniqueUsers.size,
        displayDate: new Date(day.date).toLocaleDateString('en-US', {
            month: 'short',
            day: 'numeric'
        }),
        dayName: new Date(day.date).toLocaleDateString('en-US', {
            weekday: 'short'
        })
    })).sort((a, b) => new Date(a.date) - new Date(b.date));

    // Find maximums for percentage calculations
    maxDailyLogs = Math.max(...dailyStats.map(d => d.totalLogs), 1);
    maxDailyUsers = Math.max(...dailyStats.map(d => d.uniqueUsers), 1);

    // Update summary statistics
    updateSummaryStats(uniqueUsers.size);

    // Render the appropriate view
    const currentView = document.getElementById('chartViewToggle').value;
    if (currentView === 'table') {
        renderTableView();
    } else {
        renderChartView();
    }

    // Update status
    document.getElementById('statusBadge').textContent = 'Ready';
    document.getElementById('statusBadge').className = 'badge bg-success';
}

function updateSummaryStats(uniqueUserCount) {
    const totalLogs = dailyStats.reduce((sum, day) => sum + day.totalLogs, 0);
    const avgDaily = dailyStats.length > 0 ? Math.round(totalLogs / dailyStats.length) : 0;
    const mostActiveDay = dailyStats.length > 0 ?
        dailyStats.reduce((max, day) => day.totalLogs > max.totalLogs ? day : max, dailyStats[0]) :
        null;

    document.getElementById('totalLogEntries').textContent = totalLogs.toLocaleString();
    document.getElementById('uniqueUsers').textContent = uniqueUserCount;
    document.getElementById('avgDailyActivity').textContent = avgDaily;
    document.getElementById('mostActiveDay').textContent = mostActiveDay ?
        mostActiveDay.displayDate : 'N/A';
}

function renderTableView() {
    const tbody = document.getElementById('activityTableBody');

    if (dailyStats.length === 0) {
        tbody.innerHTML = `
            <tr>
                <td colspan="6" class="text-center text-muted">
                    <i class="fas fa-search"></i> No activity data found for the selected criteria
                </td>
            </tr>
        `;
        return;
    }

    let tableRows = '';
    dailyStats.forEach(day => {
        const logPercentage = Math.round((day.totalLogs / maxDailyLogs) * 100);
        const userPercentage = Math.round((day.uniqueUsers / maxDailyUsers) * 100);

        // Create activity bar (visual representation)
        const barWidth = Math.max(logPercentage, 5); // Minimum 5% for visibility
        const barColor = day.totalLogs > (maxDailyLogs * 0.7) ? 'bg-success' :
                        day.totalLogs > (maxDailyLogs * 0.4) ? 'bg-warning' : 'bg-info';

        tableRows += `
            <tr>
                <td><strong>${day.displayDate}</strong></td>
                <td><span class="badge bg-light text-dark">${day.dayName}</span></td>
                <td class="text-center"><span class="badge bg-primary">${day.totalLogs}</span></td>
                <td class="text-center"><span class="badge bg-success">${day.uniqueUsers}</span></td>
                <td>
                    <div class="progress" style="height: 20px;">
                        <div class="progress-bar ${barColor}"
                             role="progressbar"
                             style="width: ${barWidth}%"
                             title="${day.totalLogs} logs, ${day.uniqueUsers} users">
                            ${day.totalLogs}
                        </div>
                    </div>
                </td>
                <td class="text-center">${logPercentage}%</td>
            </tr>
        `;
    });

    tbody.innerHTML = tableRows;
}

function renderChartView() {
    // Chart implementation would go here if Chart.js is available
    // For now, show a placeholder
    const chartContainer = document.getElementById('chartView');
    chartContainer.innerHTML = `
        <div class="text-center p-5">
            <i class="fas fa-chart-bar fa-3x text-muted mb-3"></i>
            <h5>Chart View</h5>
            <p class="text-muted">Chart visualization requires Chart.js library to be loaded.</p>
            <p class="text-muted">Switch to Table View to see the data in tabular format.</p>
        </div>
    `;
}

function applyUserFilter() {
    // Re-process data with new filter settings
    processLogData();
}

function toggleView() {
    const viewMode = document.getElementById('chartViewToggle').value;
    const tableView = document.getElementById('tableView');
    const chartView = document.getElementById('chartView');

    if (viewMode === 'table') {
        tableView.style.display = 'block';
        chartView.style.display = 'none';
        renderTableView();
    } else {
        tableView.style.display = 'none';
        chartView.style.display = 'block';
        renderChartView();
    }
}

// Initialize on page load
document.addEventListener('DOMContentLoaded', function() {
    // Process the log data immediately
    processLogData();
});
</script>

<style>
.progress {
    background-color: #e9ecef;
}

.progress-bar {
    transition: width 0.6s ease;
}

.badge {
    font-size: 0.85em;
}

.card {
    box-shadow: 0 0.125rem 0.25rem rgba(0, 0, 0, 0.075);
    border: 1px solid rgba(0, 0, 0, 0.125);
}

.table th {
    border-top: none;
    vertical-align: middle;
}

.table-responsive {
    max-height: 600px;
    overflow-y: auto;
}

#statusBadge {
    min-width: 80px;
    text-align: center;
}

.text-center {
    text-align: center;
}

/* Responsive adjustments */
@media (max-width: 768px) {
    .col-md-3 {
        margin-bottom: 1rem;
    }

    .table-responsive {
        font-size: 0.9em;
    }
}
</style>

<!-- DEBUG: Log data count: {{ userActivityLogs.results.entities.size }} -->
<!-- Page: lvxdata -->
