    <attribute name="lv_detail" />
    <attribute name="lv_memo" />
    <filter>
      <condition attribute="createdon" operator="last-x-days" value="30" />
    </filter>
    <order attribute="createdon" descending="false" />
  </entity>
</fetch>
{% endfetchxml %}

<!-- DEBUG: FetchXML query returned {{ userActivityLogs.results.entities.size }} records -->
<!-- DEBUG: Has entities? {% if userActivityLogs.results.entities %}YES{% else %}NO{% endif %} -->

<div class="container-fluid mt-4">
    <!-- Header -->
    <div class="row mb-4">
        <div class="col-12">
            <div class="card">
                <div class="card-header">
                    <h4 class="mb-0">
                        <i class="fas fa-chart-line"></i> User Activity Report - Last 30 Days
                    </h4>
                    <small class="text-muted">Daily activity summary for the last 30 days</small>
                </div>
            </div>
        </div>
    </div>

    <!-- Controls -->
    <div class="row mb-4">
        <div class="col-12">
            <div class="card">
                <div class="card-header">
                    <h5 class="mb-0">Filter Controls</h5>
                </div>
                <div class="card-body">
                    <div class="row g-3">
